exercise.solutionCode:
const age = 17;
let category;

if (age < 13) {
    category = "Child";
} else if (age <= 17) {
    category = "Teenager";
} else if (age <= 59) {
    category = "Adult";
} else {
    category = "Senior";
}

console.log("Age:",      age);
console.log("Category:", category);
